import{_ as a,o as l,c as i,ag as r}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"制作大纲","description":"","frontmatter":{"title":"制作大纲","outline":[2,3]},"headers":[],"relativePath":"novels/detective-manga/behind-the-scenes/outline.md","filePath":"novels/detective-manga/behind-the-scenes/outline.md","lastUpdated":1775308833000}'),e={name:"novels/detective-manga/behind-the-scenes/outline.md"};function o(n,t,d,s,h,u){return l(),i("div",null,[...t[0]||(t[0]=[r(`<h1 id="制作大纲" tabindex="-1">制作大纲 <a class="header-anchor" href="#制作大纲" aria-label="Permalink to &quot;制作大纲&quot;">​</a></h1><blockquote><p>第一季：少年包青天 · 5案10集</p></blockquote><h2 id="画风定义" tabindex="-1">画风定义 <a class="header-anchor" href="#画风定义" aria-label="Permalink to &quot;画风定义&quot;">​</a></h2><p><strong>写实国风</strong></p><ul><li>风格参考：《大理寺日志》质感 + 水墨渲染氛围</li><li>宋代考据：服饰、建筑、器物贴合北宋历史</li><li>色调体系：日常暖色为主 → 案发冷色压暗 → 推理时明暗交替 → 破案后回暖</li><li>分镜追求电影感：大特写、景深虚化、明暗光影</li></ul><h2 id="角色设定" tabindex="-1">角色设定 <a class="header-anchor" href="#角色设定" aria-label="Permalink to &quot;角色设定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>年龄</th><th>身份</th><th>漫画造型关键词</th><th>声线</th></tr></thead><tbody><tr><td><strong>包拯</strong></td><td>18</td><td>少年才子</td><td>黑面、剑眉、眼神锐利、青色书生袍、月牙胎记</td><td>沉稳偏低，偶尔冷幽默</td></tr><tr><td><strong>公孙策</strong></td><td>19</td><td>太学生，才华横溢</td><td>白衣、儒雅、瘦高、手执折扇</td><td>清朗自负</td></tr><tr><td><strong>展昭</strong></td><td>20</td><td>游侠，武功出众</td><td>窄袖劲装、佩长剑、利落短发</td><td>干脆少言</td></tr><tr><td><strong>庞飞燕</strong></td><td>17</td><td>太师之女</td><td>鲜色衣裙、活泼、大眼灵动</td><td>清脆快语</td></tr></tbody></table><h2 id="第一季选案详解" tabindex="-1">第一季选案详解 <a class="header-anchor" href="#第一季选案详解" aria-label="Permalink to &quot;第一季选案详解&quot;">​</a></h2><h3 id="第1案-名扬天下" tabindex="-1">第1案：名扬天下 <a class="header-anchor" href="#第1案-名扬天下" aria-label="Permalink to &quot;第1案：名扬天下&quot;">​</a></h3><p><strong>原案概要</strong>：科举考场中发生命案，考生离奇死亡。包拯初入考场便卷入其中，凭借观察力和推理一鸣惊人。</p><p><strong>漫剧改编要点</strong>：</p><ul><li>第1集重点：考场氛围营造、死者发现、嫌疑人浮出</li><li>第2集重点：诡计拆解的视觉化呈现、包拯推理的&quot;高光时刻&quot;</li><li>情感落点：天才少年的孤独——&quot;看穿真相的人，往往最不被理解&quot;</li></ul><p><strong>视觉亮点</strong>：</p><ul><li>考场的紧张氛围（俯拍数百考生、烛火摇曳）</li><li>推理时刻的&quot;思维宫殿&quot;可视化</li></ul><hr><h3 id="第2案-血祭坛" tabindex="-1">第2案：血祭坛 <a class="header-anchor" href="#第2案-血祭坛" aria-label="Permalink to &quot;第2案：血祭坛&quot;">​</a></h3><p><strong>原案概要</strong>：包拯等人遭遇一个与神秘祭祀有关的连环命案。阴森的祭坛、诡异的仪式、接连的死亡。</p><p><strong>漫剧改编要点</strong>：</p><ul><li>第1集重点：祭坛场景的视觉冲击、恐怖氛围、第一具尸体</li><li>第2集重点：暗道机关的还原、真凶的动机（人性层面）</li><li>情感落点：迷信与恐惧如何被利用——&quot;最可怕的不是鬼神，是人心&quot;</li></ul><p><strong>视觉亮点</strong>：</p><ul><li>祭坛全景（漫画可以做得比实拍更震撼）</li><li>暗道机关的剖面图式分解</li></ul><hr><h3 id="第3案-隐逸村之谜" tabindex="-1">第3案：隐逸村之谜 <a class="header-anchor" href="#第3案-隐逸村之谜" aria-label="Permalink to &quot;第3案：隐逸村之谜&quot;">​</a></h3><p><strong>原案概要</strong>：包拯一行进入一个与世隔绝的村庄，村中不断有人死亡，所有人都在隐瞒什么。</p><p><strong>漫剧改编要点</strong>：</p><ul><li>第1集重点：封闭空间的压迫感、村民的异常表现、谁在说谎？</li><li>第2集重点：集体秘密的层层剥开、最终反转</li><li>情感落点：集体的沉默比个人的恶更可怕</li></ul><p><strong>视觉亮点</strong>：</p><ul><li>雾气中的村庄（水墨渲染的绝佳发挥空间）</li><li>村民群像的表情特写——每个人的眼神都有秘密</li></ul><hr><h3 id="第4案-殿前扬威" tabindex="-1">第4案：殿前扬威 <a class="header-anchor" href="#第4案-殿前扬威" aria-label="Permalink to &quot;第4案：殿前扬威&quot;">​</a></h3><p><strong>原案概要</strong>：案件牵涉到朝堂，包拯需要在皇帝面前破案。政治博弈与推理交织。</p><p><strong>漫剧改编要点</strong>：</p><ul><li>第1集重点：皇宫场景的恢弘、权力的压迫感、案件的高利害</li><li>第2集重点：包拯顶住压力的推理、真相与权力的冲突</li><li>情感落点：正义与权力的碰撞——&quot;查出真相容易，说出真相才难&quot;</li></ul><p><strong>视觉亮点</strong>：</p><ul><li>金碧辉煌的大殿 vs 阴暗的密室</li><li>包拯面对满朝文武的经典画面</li></ul><hr><h3 id="第5案-五鼠闹东京" tabindex="-1">第5案：五鼠闹东京 <a class="header-anchor" href="#第5案-五鼠闹东京" aria-label="Permalink to &quot;第5案：五鼠闹东京&quot;">​</a></h3><p><strong>原案概要</strong>：五个神秘人物搅动京城，既有盗窃又有阴谋。展昭的武戏与包拯的智斗并进。</p><p><strong>漫剧改编要点</strong>：</p><ul><li>第1集重点：五鼠的分别登场、连环作案、展昭追击</li><li>第2集重点：真实目的揭露、正邪对决</li><li>情感落点：侠义与法——&quot;他们是贼，但也是被逼到绝路的人&quot;</li></ul><p><strong>视觉亮点</strong>：</p><ul><li>屋顶追逐的动作场面</li><li>五鼠各有特色的形象设计</li><li>季终大场面</li></ul><hr><h2 id="制作流程-单案" tabindex="-1">制作流程（单案） <a class="header-anchor" href="#制作流程-单案" aria-label="Permalink to &quot;制作流程（单案）&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>脚本（2天）→ 分镜草图（2天）→ AI生图+精修（3天）</span></span>
<span class="line"><span>→ 配音录制（1天）→ 音效/BGM（1天）→ 后期合成（2天）</span></span>
<span class="line"><span>→ 审核/调整（1天）</span></span></code></pre></div><p><strong>单案周期：约12天</strong><strong>第一季（5案）总周期：约2-3个月</strong>（含迭代时间）</p><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>环节</th><th>工具/方案</th></tr></thead><tbody><tr><td>脚本</td><td>AI辅助初稿 + 人工打磨</td></tr><tr><td>角色设定</td><td>AI生图（Midjourney/SD）+ 人工精修保持一致性</td></tr><tr><td>场景</td><td>AI生图 + 后期统一色调</td></tr><tr><td>分镜</td><td>手绘草图 → AI填充 → 人工调整</td></tr><tr><td>配音</td><td>真人配音（或高质量AI配音作为备选）</td></tr><tr><td>音效/BGM</td><td>素材库 + 定制</td></tr><tr><td>后期合成</td><td>剪映/PR + 转场动效</td></tr></tbody></table><h2 id="发布策略" tabindex="-1">发布策略 <a class="header-anchor" href="#发布策略" aria-label="Permalink to &quot;发布策略&quot;">​</a></h2><p><strong>平台优先级</strong>：</p><ol><li>抖音 — 流量大，短剧生态成熟</li><li>小红书 — 国风漫画截图传播力强</li><li>B站 — 核心受众聚集地</li><li>视频号 — 中年受众覆盖</li></ol><p><strong>发布节奏</strong>：</p><ul><li>每周发布1案（2集），周三第1集，周五第2集</li><li>中间穿插角色图、幕后花絮、推理互动帖</li><li>第一季10集，5周完成发布</li></ul>`,53)])])}const c=a(e,[["render",o]]);export{g as __pageData,c as default};
